import React, { useState } from 'react';

function AboutPage() {
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [selectedOptionIndex, setSelectedOptionIndex] = useState(null);
  const [score, setScore] = useState(0);
  const [showResult, setShowResult] = useState(false);
  const [resultMessage, setResultMessage] = useState('');
  const [quizComplete, setQuizComplete] = useState(false);

  // Gallery Data Arrays - Dito mo ilalagay ang listahan ng iba't ibang files mo
  const personalGallery = [
    { src: "/photos/ed6.png.jpg", alt: "Self Love 1" },
    { src: "/photos/ed7.png.jpg", alt: "Self Love 2" },
    { src: "/photos/ed8.png.jpg", alt: "Self Love 3" },
    { src: "/photos/ed9.png.png", alt: "Self Love 4" },
    { src: "/photos/ed10.png.png", alt: "Self Love 5" }
  ];

  const growthGallery = [
    { src: "/photos/ed18.png.png", alt: "Leadership 1" },
    { src: "/photos/ed19png.png", alt: "Leadership 2" },
    { src: "/photos/ed20.png.png", alt: "Leadership 3" },
    { src: "/photos/ed21.png.png", alt: "Leadership 4" }, // Siguraduhin na may ganitong files sa public/photos
    { src: "/photos/ed22.png.jpg", alt: "Leadership 5" }
  ];

  const authenticityGallery = [
    { src: "/photos/ed9.png.png", alt: "Chapter 1" },
    { src: "/photos/ed11.png.png", alt: "Chapter 2" },
    { src: "/photos/ed12.png.png", alt: "Chapter 3" }
  ];

  const quizData = [
    { question: "What is my favorite burger stall?", options: ["Angels Burger", "Out Box", "Franks", "Minute Burger"], answer: 2 },
    { question: "What is my favorite pet?", options: ["Cat", "Bird", "Snake", "Penguin"], answer: 3 },
    { question: "What is my former position in CCS student body organization?", options: ["Vice Mayor", "Peace Officer", "P.I.O", "Muse"], answer: 0 },
    { question: "What is my favorite color", options: ["Black", "Gray", "Green", "Pink"], answer: 3 },
    { question: "What is my favorite instant noodles", options: ["Lucky Me Pancit canton", "Yakisoba", "Mie Goreng", "Buldak"], answer: 2 },
    { question: "What is my usual ordered coffee", options: ["Americano", "Matcha", "Mocha", "Spanish Latte"], answer: 2 },
    { question: "How many cats do i have", options: ["3", "7", "5", "8"], answer: 1 },
    { question: "Kanino ako pinakamatagal nag move on?", options: ["Harisson", "Dwight", "Mackie", "Lester"], answer: 2 }
  ];

  const handleOptionSelect = (index) => {
    setSelectedOptionIndex(index);
  };

  const handleSubmit = () => {
    if (selectedOptionIndex === null) return;
    const currentData = quizData[currentQuestionIndex];
    if (selectedOptionIndex === currentData.answer) {
      setScore(score + 1);
      setResultMessage('Correct!');
    } else {
      setResultMessage(`Wrong! Correct answer: ${currentData.options[currentData.answer]}`);
    }
    setShowResult(true);

    setTimeout(() => {
      if (currentQuestionIndex + 1 < quizData.length) {
        setCurrentQuestionIndex(currentQuestionIndex + 1);
        setSelectedOptionIndex(null);
        setShowResult(false);
        setResultMessage('');
      } else {
        setQuizComplete(true);
      }
    }, 1500);
  };

  return (
    <main>
      {/* SECTION 1 */}
      <section className="hero">
        <h1>The Keeper of the Personal Gallery</h1>
        <p>I use the lens as a mirror to catch the light I often forget I carry...</p>
      </section>
      <section className="preview-grid">
        {personalGallery.map((img, index) => (
          <div className="card" key={index}>
            <img src={img.src} width="175" height="175" alt={img.alt} />
          </div>
        ))}
      </section>

      {/* SECTION 2 */}
      <section className="hero">
        <h1>The Curator of Collective Growth</h1>
        <p>I never intended to be the captain of the ship, but I've learned to love the rhythm of the waves...</p>
      </section>
      <section className="preview-grid">
        {growthGallery.map((img, index) => (
          <div className="card" key={index}>
            <img src={img.src} width="175" height="175" alt={img.alt} />
          </div>
        ))}
      </section>

      {/* SECTION 3 */}
      <section className="hero">
        <h1>The Mark of Authenticity</h1>
        <p>I am a collection of the books that moved me, the music that held me, and the interests that woke me up...</p>
      </section>
      <section className="preview-grid">
        {authenticityGallery.map((img, index) => (
          <div className="card" key={index}>
            <img src={img.src} width="350" height="350" alt={img.alt} />
          </div>
        ))}
      </section>

      {/* QUIZ SECTION */}
      <section className="quiz-section">
        <div className="quiz-container">
          {!quizComplete ? (
            <>
              <h2>{quizData[currentQuestionIndex].question}</h2>
              <div className="options">
                {quizData[currentQuestionIndex].options.map((option, index) => (
                  <div
                    key={index}
                    className={`option ${selectedOptionIndex === index ? 'selected' : ''}`}
                    onClick={() => handleOptionSelect(index)}
                  >
                    {option}
                  </div>
                ))}
              </div>
              <button 
                id="submitBtn" 
                onClick={handleSubmit}
                disabled={selectedOptionIndex === null}
              >
                Submit Answer
              </button>
              {showResult && <div id="result">{resultMessage}</div>}
            </>
          ) : (
            <div className="quiz-complete">
              <h2>Quiz Complete!</h2>
              <div id="result">Your final score is {score} out of {quizData.length}.</div>
              <button onClick={() => window.location.reload()} className="btn">Restart Quiz</button>
            </div>
          )}
        </div>
      </section>

      <footer>
        <p>&copy; Cead. All rights reserved. | Contact: edrickbillones0@gmail.com</p>
      </footer>
    </main>
  );
}

export default AboutPage;
